+  private readonly metrics: MetricsCollector;

-  constructor(db: Database, cache: CacheClient) {
+  constructor(deps: OrdersDeps) {
+    const { db, cache, logger, metrics } = deps;
     this.db = db;
     this.cache = cache;
-    this.logger = new Logger("orders");
+    this.logger = logger.child({ service: "orders" });
+    this.metrics = metrics;
   }

-  async findById(id: string) {
-    const cached = await this.cache.get(id);
-    if (cached) return cached;
-    const row = await this.db.query("SELECT * FROM orders WHERE id = $1", [id]);
-    if (row) await this.cache.set(id, row, 300);
-    return row;
+  async findById(id: string): Promise<Orders | null> {
+    const timer = this.metrics.startTimer("orders_find_by_id");
+    try {
+      const cached = await this.cache.get<Orders>(`orders:${id}`);
